import java.io.IOException;

public class CommandInjectionSecure {

    public static void main(String[] args) {
        String userInput = "example.txt; ls -la";

        // Validate user input to ensure it contains only allowed characters (alphanumeric, dot, underscore, etc.)
        if (!userInput.matches("[a-zA-Z0-9._-]+")) {
            System.err.println("Invalid input");
            return;
        }

        try {
            // Execute a command using ProcessBuilder with sanitized arguments
            Process process = new ProcessBuilder("cat", userInput).start();

            // Read the output of the command
            int c;
            while ((c = process.getInputStream().read()) != -1) {
                System.out.print((char)c);
            }

            process.waitFor();
        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }

}

